/**
 * Generates src/build-info.js with the current semantic version (from
 * package.json), the short git commit hash, and the UTC build date/time.
 *
 * This script is run automatically by the npm lifecycle hooks `predev`,
 * `prebuild`, and `pretest`, so the generated file is always up-to-date
 * before the dev server starts, the production bundle is built, or the
 * test suite runs.
 *
 * The generated file is listed in .gitignore — only this script and the
 * placeholder fallback in AppVersion.js are tracked in version control.
 */
import { execSync } from 'child_process';
import { readFileSync, writeFileSync } from 'fs';

const pkg = JSON.parse(readFileSync('./package.json', 'utf-8'));

const commit = (() => {
  try {
    return execSync('git rev-parse --short HEAD').toString().trim();
  } catch {
    // Fallback for environments where git history is unavailable.
    return 'unknown';
  }
})();

const buildDate = new Date().toISOString().replace('T', ' ').slice(0, 16) + ' UTC';

writeFileSync(
  'src/build-info.js',
  `// Auto-generated by scripts/gen-build-info.js — do not edit manually.
// Regenerated on every \`npm run dev\`, \`npm run build\`, and \`npm test\`.
export const APP_VERSION = ${JSON.stringify(pkg.version)};
export const GIT_COMMIT  = ${JSON.stringify(commit)};
export const BUILD_DATE  = ${JSON.stringify(buildDate)};
`,
);

console.log(`[build-info] v${pkg.version} (${commit}) ${buildDate}`);
